	@Test
	void rewritesDuplicateInsensitiveFiniteMembershipAsEarlyJoin() {
		BindingSetAssignment names = values("optName", "user0", "user1", "user2");
		StatementPattern name = statementPattern("a", "name", "optName");
		TupleExpr cycle = new Extension(
				new Join(new Join(statementPattern("a", "follows", "b"), statementPattern("b", "follows", "c")),
						statementPattern("c", "follows", "a")),
				new ExtensionElem(new Var("a"), "cycleStart"));
		Group group = new Group(new Join(new Join(names, name), cycle));
		group.addGroupElement(new GroupElem("count", new Count(new Var("a"), true)));
		QueryRoot root = new QueryRoot(group);

		new LmdbSetSemanticsOptimizer().optimize(root, null, null);

		Group optimizedGroup = assertInstanceOf(Group.class, root.getArg(), () -> root.toString());
		Join optimizedJoin = assertInstanceOf(Join.class, optimizedGroup.getArg(), () -> root.toString());
		assertTrue(containsBindingSetAssignmentFor(optimizedJoin.getLeftArg(), "optName"), () -> root.toString());
		assertTrue(containsStatementPatternWithObject(optimizedJoin.getLeftArg(), "optName"), () -> root.toString());
		assertInstanceOf(Extension.class, optimizedJoin.getRightArg(), () -> root.toString());
		assertFalse(containsFilter(optimizedJoin), () -> root.toString());
		assertFalse(containsExists(optimizedJoin), () -> root.toString());
		assertRewriteCertificate(optimizedJoin, "DISTINCT_FINITE_MEMBERSHIP_SEMI_FILTER", "23", "false");
	}

	@Test
	void keepsFiniteMembershipPatternWhenDistinctCountUsesPatternLocalVariable() {
		BindingSetAssignment names = values("optName", "user0", "user1");
		StatementPattern membership = new StatementPattern(new Var("a"), new Var("membershipPredicate"),
				new Var("optName"), new Var("link"));
		StatementPattern correlatedRemainder = statementPattern("a", "follows", "link");
		Group group = new Group(new Join(new Join(names, membership), correlatedRemainder));
		group.addGroupElement(new GroupElem("aCount", new Count(new Var("a"), true)));
		group.addGroupElement(new GroupElem("predicateCount", new Count(new Var("membershipPredicate"), true)));
		QueryRoot root = new QueryRoot(group);

		new LmdbSetSemanticsOptimizer().optimize(root, null, null);

		Group optimizedGroup = assertInstanceOf(Group.class, root.getArg(), () -> root.toString());
		assertFalse(containsExists(optimizedGroup.getArg()),
				() -> "A DISTINCT-counted variable local to the membership pattern must stay row-producing: "
						+ root);
		assertTrue(containsStatementPatternWithPredicate(optimizedGroup.getArg(), "membershipPredicate"),
				() -> root.toString());
	}

	private static QueryRoot optimizeBeforeSketch(TupleExpr tupleExpr) {
		QueryRoot root = new QueryRoot(tupleExpr);
		TripleSource tripleSource = new EmptyTripleSource();
		StrictEvaluationStrategy strategy = new StrictEvaluationStrategy(tripleSource, null);
		for (QueryOptimizer optimizer : new LmdbQueryOptimizerPipeline(strategy, tripleSource,
				new EvaluationStatistics()).getOptimizers()) {
			if (optimizer instanceof LmdbCascadesOptimizer) {
				break;
			}
			optimizer.optimize(root, null, EmptyBindingSet.getInstance());
		}
		return root;
	}

	private static QueryRoot optimizeSetSemantics(TupleExpr tupleExpr) {
		QueryRoot root = new QueryRoot(tupleExpr);
		new LmdbSetSemanticsOptimizer().optimize(root, null, null);
		return root;
	}

	private static StatementPattern statementPattern(String subjectName, String predicateName, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var(predicateName, VF.createIRI("urn:" + predicateName)),
				new Var(objectName));
	}

	private static StatementPattern constantStatementPattern(String subject, String predicate, String object) {
		return new StatementPattern(TupleExprs.createConstVar(VF.createIRI("urn:" + subject)),
				TupleExprs.createConstVar(VF.createIRI("urn:" + predicate)),
				TupleExprs.createConstVar(VF.createIRI("urn:" + object)));
	}

	private static BindingSetAssignment values(String bindingName, String... values) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(Set.of(bindingName));
		List<BindingSet> bindingSets = new ArrayList<>(values.length);
		for (String value : values) {
			MapBindingSet bindingSet = new MapBindingSet(1);
			bindingSet.addBinding(bindingName, VF.createLiteral(value));
			bindingSets.add(bindingSet);
		}
		assignment.setBindingSets(bindingSets);
		return assignment;
	}

	private static int countBindingSets(BindingSetAssignment assignment) {
		int count = 0;
		for (BindingSet ignored : assignment.getBindingSets()) {
			count++;
		}
		return count;
	}

	private static boolean containsBindingSetAssignmentFor(TupleExpr tupleExpr, String bindingName) {
		if (tupleExpr instanceof BindingSetAssignment) {
			return ((BindingSetAssignment) tupleExpr).getBindingNames().contains(bindingName);
		}
		if (tupleExpr instanceof Filter filter) {
			return containsBindingSetAssignmentFor(filter.getArg(), bindingName);
		}
		if (tupleExpr instanceof Extension extension) {
			return containsBindingSetAssignmentFor(extension.getArg(), bindingName);
		}
		if (tupleExpr instanceof LeftJoin leftJoin) {
			return containsBindingSetAssignmentFor(leftJoin.getLeftArg(), bindingName)
					|| containsBindingSetAssignmentFor(leftJoin.getRightArg(), bindingName);
		}
		if (tupleExpr instanceof Join join) {
			return containsBindingSetAssignmentFor(join.getLeftArg(), bindingName)
					|| containsBindingSetAssignmentFor(join.getRightArg(), bindingName);
		}
		return false;
	}

	private static boolean containsStatementPatternWithObject(TupleExpr tupleExpr, String objectName) {
		if (tupleExpr instanceof StatementPattern) {
			return objectName.equals(((StatementPattern) tupleExpr).getObjectVar().getName());
		}
		if (tupleExpr instanceof Filter filter) {
			return containsStatementPatternWithObject(filter.getArg(), objectName);
		}
		if (tupleExpr instanceof Extension extension) {
			return containsStatementPatternWithObject(extension.getArg(), objectName);
		}
		if (tupleExpr instanceof LeftJoin leftJoin) {
			return containsStatementPatternWithObject(leftJoin.getLeftArg(), objectName)
					|| containsStatementPatternWithObject(leftJoin.getRightArg(), objectName);
		}
		if (tupleExpr instanceof Join join) {
			return containsStatementPatternWithObject(join.getLeftArg(), objectName)
					|| containsStatementPatternWithObject(join.getRightArg(), objectName);
		}
		return false;
	}

	private static boolean containsStatementPatternWithPredicate(TupleExpr tupleExpr, String predicateName) {
		if (tupleExpr instanceof StatementPattern) {
			return predicateName.equals(((StatementPattern) tupleExpr).getPredicateVar().getName());
		}
		if (tupleExpr instanceof Filter filter) {
			return containsStatementPatternWithPredicate(filter.getArg(), predicateName);
		}
		if (tupleExpr instanceof Extension extension) {
			return containsStatementPatternWithPredicate(extension.getArg(), predicateName);
		}
		if (tupleExpr instanceof LeftJoin leftJoin) {
			return containsStatementPatternWithPredicate(leftJoin.getLeftArg(), predicateName)
					|| containsStatementPatternWithPredicate(leftJoin.getRightArg(), predicateName);
		}
		if (tupleExpr instanceof Join join) {
			return containsStatementPatternWithPredicate(join.getLeftArg(), predicateName)
					|| containsStatementPatternWithPredicate(join.getRightArg(), predicateName);
		}
		return false;
	}

	private static boolean containsFilter(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Filter) {
			return true;
		}
		if (tupleExpr instanceof Extension extension) {
			return containsFilter(extension.getArg());
		}
		if (tupleExpr instanceof LeftJoin leftJoin) {
			return containsFilter(leftJoin.getLeftArg()) || containsFilter(leftJoin.getRightArg());
		}
		if (tupleExpr instanceof Join join) {
			return containsFilter(join.getLeftArg()) || containsFilter(join.getRightArg());
		}
		return false;
	}

	private static boolean containsExists(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Filter filter) {
			return filter.getCondition() instanceof Exists || containsExists(filter.getArg());
		}
		if (tupleExpr instanceof Extension extension) {
			return containsExists(extension.getArg());
		}
		if (tupleExpr instanceof LeftJoin leftJoin) {
			return containsExists(leftJoin.getLeftArg()) || containsExists(leftJoin.getRightArg());
		}
		if (tupleExpr instanceof Join join) {
			return containsExists(join.getLeftArg()) || containsExists(join.getRightArg());
		}
		return false;
	}

	private static void assertRewriteCertificate(TupleExpr tupleExpr, String kind, String ruleId,
			String preservedMultiplicity) {
		String proof = tupleExpr.getStringMetricPlanned("optimizer.rewriteProof");
		assertNotNull(proof);
		assertTrue(proof.contains("proofKind=" + kind), proof);
		assertTrue(proof.contains("rule=" + ruleId), proof);
		assertTrue(proof.contains("preservedVisibleVars=true"), proof);
		assertTrue(proof.contains("preservedMultiplicity=" + preservedMultiplicity), proof);
		assertTrue(proof.contains("preservedOrder=true"), proof);
		assertTrue(proof.contains("preservedErrors=true"), proof);
		assertTrue(proof.contains("preservedGraphScope=true"), proof);
		assertTrue(proof.contains("DUPLICATE_INSENSITIVE_CONTEXT"), proof);
	}

	private static final class EmptyTripleSource implements TripleSource {

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred, Value obj,
				Resource... contexts) throws QueryEvaluationException {
			return EMPTY_ITERATION;
		}

		@Override
		public ValueFactory getValueFactory() {
			return VF;
		}
	}
